const items = $input.all();

return items.flatMap(item => {
  if (!item.json.response) return [];
  const fixtureId = item.json.parameters?.fixture;

  return item.json.response.map(event => ({
    json: {
      fixture_id:      fixtureId,
      minute:          event.time.elapsed,
      extra_time:      event.time.extra || null,
      team_external_id: event.team.id,
      team_name:       event.team?.name || null,
      player_id:       event.player?.id || null,
      player_name:     event.player?.name || null,
      assist_id:       event.assist?.id || null,
      assist_name:     event.assist?.name || null,
      type:            event.type,
      detail:          event.detail,
      comments:        event.comments || null
    }
  }));
});

const TYPE_MAP = {
  'Goal':  'goal',
  'Card':  'yellow_card',
  'subst': 'substitution',
  'Var':   'comment',
  'Miss':  'missed_penalty',
};

function normalizeType(type, detail) {
  if (type === 'Card') {
    const d = (detail || '').toLowerCase();
    if (d.includes('red')) return 'red_card';
    return 'yellow_card';
  }
  return TYPE_MAP[type] || 'comment';
}

function esc(val) {
  if (val === null || val === undefined) return 'NULL';
  return `'${String(val).replace(/'/g, "''")}'`;
}

function num(val) {
  return (val === null || val === undefined) ? 'NULL' : val;
}

return $input.all().map(item => {
  const e = item.json;
  const eventType = normalizeType(e.type, e.detail);

  const sourceId = `apifootball_${e.fixture_id}_${e.minute}_${e.type}_${e.player_id ?? 'x'}`;

  const description = JSON.stringify({
    player_id:   e.player_id,
    player_name: e.player_name,
    assist_id:   e.assist_id,
    assist_name: e.assist_name,
    team_id:     e.team_external_id,
    team_name:   e.team_name,
    type:        e.type,
    detail:      e.detail,
    comments:    e.comments,
  });

  const query = `
    INSERT INTO events (
      match_id, time, time_additional,
      event_type, description, source, source_id
    )
    VALUES (
      (SELECT id FROM matches WHERE external_id = ${num(e.fixture_id)}::integer),
      ${num(e.minute)},
      ${num(e.extra_time)},
      ${esc(eventType)},
      ${esc(description)},
      'api_football',
      ${esc(sourceId)}
    )
    ON CONFLICT (source_id) WHERE source_id IS NOT NULL
    DO UPDATE SET source_id = EXCLUDED.source_id
    RETURNING id, event_type, time, description
  `.trim();

  return { json: { query, fixture_id: e.fixture_id } };
});

function esc(v) {
  return `'${String(v).replace(/'/g, "''")}'`;
}

return $input.all().flatMap(item => {
  const e = item.json;
  const desc = typeof e.description === 'string'
    ? JSON.parse(e.description)
    : (e.description ?? {});

  // Nur Tore die Frankfurt selbst schießt
  const teamName = (desc.team_name || '').toLowerCase();
  if (!teamName.includes('frankfurt')) return [];

  const playerName = desc.player_name;
  if (!playerName) return [];

  // API Football: 'M. Batshuayi' → lastName = 'Batshuayi'
  const parts = playerName.trim().split(/\s+/);
  const lastName = parts[parts.length - 1];

  const eventTime = e.time ?? null;

  const query = `
    SELECT video_url, display_name, ${eventTime !== null ? eventTime : 'NULL'} AS event_time
    FROM players
    WHERE video_url IS NOT NULL
      AND team_id IN (SELECT id FROM teams WHERE name ILIKE '%Frankfurt%')
      AND (
        display_name ILIKE ${esc('%' + lastName + '%')}
        OR display_name ILIKE ${esc('%' + playerName + '%')}
      )
    LIMIT 1
  `.trim();

  return [{ json: { query, player_name: playerName, event_id: e.id, event_time: eventTime } }];
});
